SELECT COUNT(access_id) AS access_count
FROM job_access_logs
WHERE user_id = 1 AND job_instance_id = 0;

SELECT job_name
FROM job_instances
ORDER BY job_name;

SELECT user_name
FROM job_users
WHERE user_status = 'active';

SELECT COUNT(access_id) AS access_count
FROM job_access_logs
WHERE job_instance_id = 1;

SELECT job_name
FROM job_instances
ORDER BY job_name;

SELECT job_name, creation_date
FROM job_instances
ORDER BY creation_date DESC;

SELECT COUNT(DISTINCT job_instance_id) AS job_instance_count
FROM (
    SELECT job_instance_id FROM job_access_logs WHERE user_id = 0
    UNION
    SELECT job_instance_id FROM job_audit_logs WHERE user_id = 0
);

SELECT MAX(access_date)
FROM job_access_logs
WHERE job_instance_id = 1;
